// Script: generar_39_fix_scroll_overlay_correcto.js
// Que hace: corrige el bug de que no se podia hacer scroll DENTRO del
// modal para llegar al boton Guardar/Eliminar. El fix anterior bloqueo
// correctamente el fondo, pero el scroll interno del modal seguia sin
// funcionar por una causa especifica: el overflow-y-auto estaba en el
// contenedor INTERNO del modal, cuando segun la forma correcta de hacer
// esto (confirmada en documentacion tecnica), el overflow-y-auto debe
// estar en la capa EXTERIOR (el overlay oscuro de fondo), no en la caja
// del modal.
//
// Se corrigieron los 3 lugares: el modal de acciones y el de
// crear/editar en Prevencion, el mini-formulario de Cuidados en
// Registro Diario, y el modal de Registrar Peso.
//
// Como correrlo: node generar_39_fix_scroll_overlay_correcto.js
// Confirma "OK" para los 3 archivos

const fs = require('fs');
const path = require('path');

function escribir(relPath, b64) {
  const filePath = path.join(...relPath.split('/'));
  const content = Buffer.from(b64, 'base64').toString('utf8');
  const dir = path.dirname(filePath);
  if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, 'utf8');
  console.log('OK: ' + filePath);
}

escribir('app/prevencion/page.tsx', "");
escribir('app/registro-diario/page.tsx', "");
escribir('components/PesoTracker.tsx', "");
